from pybricks.hubs import PrimeHub
from pybricks.parameters import Direction, Port
from pybricks.pupdevices import Motor
from pybricks.robotics import DriveBase

# Set up.
prime_hub = PrimeHub()
left = Motor(Port.E, Direction.COUNTERCLOCKWISE)
right = Motor(Port.A, Direction.CLOCKWISE)
robot = DriveBase(left, right, 56, 130)
turns = 1
temp = 0
testscore = 0

def Tank_Turn(Speed, orientation):
    global turns, temp, testscore
    turns = 1
    robot.settings(turn_rate=Speed)
    for count in range(4):
        robot.use_gyro(True)
        temp = abs(0) + 90 * turns
        robot.turn(orientation * 90)
        prime_hub.speaker.beep(500, 100)
        turns = turns + 1
    print('Testing Result: Speed=', Speed, 'Delta=', abs(prime_hub.imu.heading()) - 360)
    testscore = testscore + (abs(prime_hub.imu.heading()) - 360)


# The main program starts here.
print('Starting Test')
Tank_Turn(50, -1)
Tank_Turn(50, 1)
Tank_Turn(75, -1)
Tank_Turn(75, 1)
Tank_Turn(100, -1)
Tank_Turn(100, 1)
print('Test score', 100 - testscore)
